const input = "   Ahmad@Mail.COM  ";
const clean = input.trim().toLowerCase();
console.log(clean);              // ahmad@mail.com
console.log(String(7).padStart(2, "0")); // "07"

const text = "تعلم HTML ثم تعلم CSS";

console.log(text.includes("CSS"));       // true
console.log(text.replace("تعلم", "أتقن"));    // أول واحدة فقط
console.log(text.replaceAll("تعلم", "أتقن")); // كلها

const words = text.split(" ");
console.log(words, "عدد الكلمات:", words.length);

const name = "سارة";
const score = 95;

// الطريقة القديمة المتعبة:
console.log("الطالبة " + name + " حصلت على " + score);

// القالب النصي الحديث:
console.log(`الطالبة ${name} حصلت على ${score}`);
console.log(`الناتج المحسوب: ${score * 2}`);
